code = """import json, re
import pandas as pd

# Load mongo result (may be file path)
biz_src = var_call_Jgjro81WqnB6NB0y5Jq0Ic2k
if isinstance(biz_src, str):
    with open(biz_src, 'r') as f:
        biz = json.load(f)
else:
    biz = biz_src

biz_df = pd.DataFrame(biz)

# Extract state from description: look for ', XX,' or ', XX.'
state_re = re.compile(r",\s*([A-Z]{2})\b")

def extract_state(desc):
    if not isinstance(desc, str):
        return None
    m = state_re.findall(desc)
    if not m:
        return None
    # heuristic: take last 2-letter token; filter to US states/DC
    us_states = set(['AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY','DC'])
    for code in reversed(m):
        if code in us_states:
            return code
    return None

biz_df['state'] = biz_df['description'].map(extract_state)

# Determine offers WiFi: attribute WiFi value is not 'no'

def offers_wifi(attr):
    if not isinstance(attr, dict):
        return False
    v = attr.get('WiFi')
    if v is None:
        return False
    if isinstance(v, str):
        vv = v.strip().lower()
        # normalize strings like "u'free'" and "'no'"
        vv = vv.replace("u'", "'")
        vv = vv.strip("\"")
        vv = vv.strip()
        # extract inside quotes if present
        m = re.match(r"^'?([^']+)'?$", vv)
        if m:
            vv2 = m.group(1)
        else:
            vv2 = vv
        vv2 = vv2.strip().lower()
        return vv2 != 'no'
    return True

biz_df['offers_wifi'] = biz_df['attributes'].map(offers_wifi)

wifi_biz_df = biz_df[(biz_df['offers_wifi']) & (biz_df['state'].notna())][['business_id','state']].drop_duplicates()

# Count by state
state_counts = wifi_biz_df.groupby('state').size().reset_index(name='wifi_businesses')
state_counts = state_counts.sort_values(['wifi_businesses','state'], ascending=[False, True])

top_state = state_counts.iloc[0]['state']

# Map business_id -> business_ref
wifi_biz_df['business_ref'] = wifi_biz_df['business_id'].str.replace('businessid_', 'businessref_', regex=False)

ratings_df = pd.DataFrame(var_call_P2Ltf3dLP8zEhVxoGy0OXG10)
ratings_df['avg_rating'] = ratings_df['avg_rating'].astype(float)

# Join ratings for businesses in top state
join_df = wifi_biz_df[wifi_biz_df['state']==top_state].merge(ratings_df, on='business_ref', how='left')
# average rating across those businesses with at least one review
avg_rating_top_state = join_df['avg_rating'].mean(skipna=True)

result = {
    'state': top_state,
    'wifi_business_count': int(state_counts.iloc[0]['wifi_businesses']),
    'average_rating': None if pd.isna(avg_rating_top_state) else float(avg_rating_top_state)
}

print('__RESULT__:')
print(json.dumps(result))"""

